local 简单_决战大雁塔 = class()
local qz=math.floor
function 简单_决战大雁塔:初始化()

end


function 简单_决战大雁塔:系统胜利处理(胜利组,失败组)
	for n=1,#胜利组 do
    local id=胜利组[n]
    local 平均等级 = 取队伍平均等级(玩家数据[id].队伍,id)
		local 决战进阶 = 30
		local 决战积分 = 10
    local 经验=平均等级*取随机数(2200,2300)
    local 银子=平均等级*160+24000
    玩家数据[id].角色:添加经验(经验*HDPZ["决战大雁塔"].经验,"决战大雁塔",1)
    玩家数据[id].角色:添加银子(qz(银子*HDPZ["决战大雁塔"].银子),"决战大雁塔",1)
    玩家数据[id].角色:添加储备(qz(银子*0.2*HDPZ["决战大雁塔"].银子),"决战大雁塔",1)
    if 取随机数()<=HDPZ["决战大雁塔"].爆率 then
        local 链接 = {提示=format("#S(决战大雁塔守护者)#R/%s#Y经过一番激烈的战斗，最终战胜了#R守护者#Y，#Y因此获得了唐王奖励的#G/",玩家数据[id].角色.名称),频道="xt",结尾="#"..取随机数(1,110)}
        local 名称,数量,参数=糖果生成产出(糖果产出物品计算(HDPZ["决战大雁塔"].ITEM),"决战大雁塔")
        if 数量== 9999 then --环
            玩家数据[id].道具:给予道具(id,nil,nil,nil,nil,nil,名称,nil,nil,nil,链接)
        else
            玩家数据[id].道具:给予超链接道具(id,名称,数量,参数,链接)
        end
    end
    if 玩家数据[id].角色.决战积分==nil then
			玩家数据[id].角色.决战积分=0
		end
		if 玩家数据[id].角色.决战积分 < 决战进阶 then
	    玩家数据[id].角色.决战积分=玩家数据[id].角色.决战积分+决战积分
		  常规提示(id,"#Y/恭喜你战胜了(守护神)获得了"..决战积分.."点决战积分")
		else
			local 升降地图={[10041]=1,[10051]=2,[10061]=3,[10071]=4,[10081]=5,[10901]=6,[10091]=7}
		  local 升降地图1={[1]=10041,[2]=10051,[3]=10061,[4]=10071,[5]=10081,[6]=10901,[7]=10091}
			local 胜利编号 = 升降地图[玩家数据[id].角色.地图数据.编号] +1
			if 胜利编号> 7 then
				胜利编号=7
			end
			玩家数据[id].zhandou=0
			地图处理类:跳转地图(id,升降地图1[胜利编号],32,36)
		  玩家数据[id].角色.决战积分=玩家数据[id].角色.决战积分-决战进阶
		  常规提示(id,"#Y/恭喜你进阶至"..胜利编号.."层，扣除了"..决战进阶.."决战积分")
		end
	end
end

