		for n=1,#胜利组 do
	    local 胜利id=胜利组[n]
	    local 平均等级 = 取队伍平均等级(玩家数据[胜利id].队伍,胜利id)
	    local 升降地图={[10041]=1,[10051]=2,[10061]=3,[10071]=4,[10081]=5,[10901]=6,[10091]=7}
	    local 升降地图1={[1]=10041,[2]=10051,[3]=10061,[4]=10071,[5]=10081,[6]=10901,[7]=10091}
	    local 胜利编号= 升降地图[玩家数据[胜利组[1]].角色.地图数据.编号] +1
