function 简单_决战大雁塔:对话事件处理(id,名称,事件,类型)
	if 玩家数据[id].队伍==0  then return 	常规提示(id,"#Y/非5人队伍，无法进行挑战") end
	if  取队伍人数(id)~=5   then return 	常规提示(id,"#Y/非5人队伍，无法进行挑战") end
	if 事件=="我想继续往上走" then
		self:大雁塔挑战(id,1+((类型-1350)*0.5))
	end
end


function 简单_决战大雁塔:大雁塔挑战(id,难度系数)
	 local 队伍id=玩家数据[id].队伍

	 local 雁塔假人属性 = {}
    		 for n=1,#队伍数据[队伍id].成员数据 do
		              local 队员id=队伍数据[队伍id].成员数据[n]
		              if 玩家数据[队员id]~=nil then
		                local 武器伤害 = 0
		                if 玩家数据[队员id].角色.装备[3]~=nil and 玩家数据[队员id].道具.数据[玩家数据[队员id].角色.装备[3]] then
		                  local 临时武器=table.loadstring(table.tostring(玩家数据[队员id].道具.数据[玩家数据[队员id].角色.装备[3]]))
		                  if not 临时武器.命中 then 临时武器.命中=1 end
		                  武器伤害=qz(临时武器.伤害+临时武器.命中*0.3)
		                end
		                雁塔假人属性[#雁塔假人属性+1]={
		                  名称=取随机中文姓名(取随机数(2,5)),
		                  模型=玩家数据[队员id].角色.模型,
		                  等级=玩家数据[队员id].角色.等级,
		                  气血=12000*难度系数,
		                  魔法=2000*难度系数,
		                  伤害=3600*难度系数,
		                  法伤=2000*难度系数,
		                  速度=1200*难度系数,
		                  防御=2000*难度系数,
		                  法防=2000*难度系数,
		                  治疗能力=800*难度系数,
		                  固定伤害=800*难度系数,
		                  攻击修炼=玩家数据[队员id].角色.修炼.攻击修炼[1],
		                  法术修炼=玩家数据[队员id].角色.修炼.法术修炼[1],
		                  防御修炼=玩家数据[队员id].角色.修炼.防御修炼[1],
		                  抗法修炼=玩家数据[队员id].角色.修炼.抗法修炼[1],
		                  角色=true,
		                  门派=玩家数据[队员id].角色.门派,
		                  五维属性={体质=玩家数据[队员id].角色.体质,魔力=玩家数据[队员id].角色.魔力,力量=玩家数据[队员id].角色.力量,耐力=玩家数据[队员id].角色.耐力,敏捷=玩家数据[队员id].角色.敏捷},
		                  武器伤害=武器伤害,
		                  位置=n,
		                }


		             if not 判断是否为空表(玩家数据[队员id].角色.参战宝宝) then
		                  雁塔假人属性[#雁塔假人属性+1]={
		                    名称=玩家数据[队员id].角色.参战宝宝.模型,
		                    模型=玩家数据[队员id].角色.参战宝宝.模型,
		                    等级=玩家数据[队员id].角色.参战宝宝.等级,
		                             气血=12000*难度系数,
			                  魔法=2000*难度系数,
			                  伤害=3600*难度系数,
			                  法伤=2000*难度系数,
			                  速度=1200*难度系数,
			                  防御=2000*难度系数,
			                  法防=2000*难度系数,
		                    攻击修炼=玩家数据[队员id].角色.bb修炼.攻击控制力[1],
		                    法术修炼=玩家数据[队员id].角色.bb修炼.法术控制力[1],
		                    防御修炼=玩家数据[队员id].角色.bb修炼.防御控制力[1],
		                    抗法修炼=玩家数据[队员id].角色.bb修炼.抗法控制力[1],
		                    技能=玩家数据[队员id].角色.参战宝宝.技能,
		                    参战等级=玩家数据[队员id].角色.参战宝宝.参战等级,
		                    五维属性={体质=玩家数据[队员id].角色.参战宝宝.体质,魔力=玩家数据[队员id].角色.参战宝宝.魔力,力量=玩家数据[队员id].角色.参战宝宝.力量,耐力=玩家数据[队员id].角色.参战宝宝.耐力,敏捷=玩家数据[队员id].角色.参战宝宝.敏捷},
		                    位置=n+5
		                  }
		             end

	         	       		for k,v in pairs(玩家数据[id].召唤兽.数据) do
	         	       			if v.参战名称==玩家数据[队员id].角色.名称 and v.参战id==队员id then
				                  雁塔假人属性[#雁塔假人属性+1]={
				                    名称=v.模型,
				                    模型=v.模型,
				                    等级=v.等级,
				                   气血=12000*难度系数,
				                  魔法=2000*难度系数,
				                  伤害=3600*难度系数,
				                  法伤=2000*难度系数,
				                  速度=1200*难度系数,
				                  防御=2000*难度系数,
				                  法防=2000*难度系数,
				                    攻击修炼=玩家数据[队员id].角色.bb修炼.攻击控制力[1],
				                    法术修炼=玩家数据[队员id].角色.bb修炼.法术控制力[1],
				                    防御修炼=玩家数据[队员id].角色.bb修炼.防御控制力[1],
				                    抗法修炼=玩家数据[队员id].角色.bb修炼.抗法控制力[1],
				                    技能=v.技能,
				                    参战等级=v.参战等级,
				                    五维属性={体质=v.体质,魔力=v.魔力,力量=v.力量,耐力=v.耐力,敏捷=v.敏捷},
				                    位置=n+5
				                  }
				              end
				end

		end
	end
	战斗准备类:创建战斗(id,154000,0,nil,雁塔假人属性)
end
